class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

public String findPath(TreeNode root, int target, String path) {
    if (root == null) return "";
    if (root.val == target) return path;
    String left = findPath(root.left, target, path + "L");
    String right = findPath(root.right, target, path + "R");
    return left.isEmpty() ? right : left;
}

public String shortestPath(TreeNode root, int startValue, int destValue) {
    String sPath = findPath(root, startValue, "");
    String tPath = findPath(root, destValue, "");
    int i = 0;
    while (i < sPath.length() && i < tPath.length() && sPath.charAt(i) == tPath.charAt(i)) i++;
    String res = "";
    for (int j = sPath.length() - 1; j >= i; j--) res += "U";
    for (int j = i; j < tPath.length(); j++) res += tPath.charAt(j);
    return res;
}
```

